  1→/// A validated email address.
  2→///
  3→/// Constructed via `ValidatedEmail::parse()`. The email is normalized to lowercase
  4→/// (case-insensitive per US-2). This type carries proof of validation -- once you
  5→/// have a `ValidatedEmail`, you know it passed format checks.
  6→#[derive(Debug, Clone, PartialEq, Eq)]
  7→pub struct ValidatedEmail(String);
  8→
  9→impl ValidatedEmail {
 10→    pub fn parse(input: String) -> Result<Self, EmailValidationError> {
 11→        let trimmed = input.trim().to_string();
 12→
 13→        if trimmed.is_empty() {
 14→            return Err(EmailValidationError::Empty);
 15→        }
 16→
 17→        if trimmed.len() > 254 {
 18→            return Err(EmailValidationError::TooLong);
 19→        }
 20→
 21→        if !trimmed.contains('@') {
 22→            return Err(EmailValidationError::MissingAtSymbol);
 23→        }
 24→
 25→        let parts: Vec<&str> = trimmed.splitn(2, '@').collect();
 26→        let local = parts[0];
 27→        let domain = parts[1];
 28→
 29→        if local.is_empty() || domain.is_empty() {
 30→            return Err(EmailValidationError::MissingAtSymbol);
 31→        }
 32→
 33→        if !domain.contains('.') {
 34→            return Err(EmailValidationError::MissingAtSymbol);
 35→        }
 36→
 37→        Ok(Self(trimmed.to_lowercase()))
 38→    }
 39→
 40→    pub fn as_str(&self) -> &str {
 41→        &self.0
 42→    }
 43→}
